class PaymentProcessor {
  final String _gatewayUrl = "YOUR_PAYMENT_GATEWAY_URL"; // Replace with your payment gateway
  final InAppPurchase _inAppPurchase = InAppPurchase.instance;

  Future<void> initialize() async {
    final bool available = await _inAppPurchase.isAvailable();
    if (!available) {
      throw Exception("In-app purchases not available");
    }
  }

  Future<List<ProductDetails>> fetchProducts(Set<String> productIds) async {
    final ProductDetailsResponse response = await _inAppPurchase.queryProductDetails(productIds);
    if (response.notFoundIDs.isNotEmpty) {
      throw Exception("Product not found");
    }
    return response.productDetails;
  }

  Future<void> purchaseProduct(ProductDetails productDetails) async {
    final PurchaseParam purchaseParam = PurchaseParam(productDetails: productDetails);
    await _inAppPurchase.buyConsumable(purchaseParam: purchaseParam);
  }

  Future<void> verifyPayment(String receipt) async {
    final response = await http.post(
      Uri.parse(_gatewayUrl),
      headers: {"Content-Type": "application/json"},
      body: '{"receipt": "$receipt"}',
    );
    if (response.statusCode != 200) {
      throw Exception("Payment verification failed");
    }
  }
}

